package com.xoxo.pos.config;
import com.xoxo.pos.products.*;import com.xoxo.pos.tables.*;import com.xoxo.pos.users.*;import org.springframework.boot.CommandLineRunner;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Component;import java.math.BigDecimal;
@Component public class DataSeeder implements CommandLineRunner{private final UserRepository users;private final PasswordEncoder enc;private final ProductRepository products;private final BarTableRepository tables;public DataSeeder(UserRepository users,PasswordEncoder enc,ProductRepository products,BarTableRepository tables){this.users=users;this.enc=enc;this.products=products;this.tables=tables;}public void run(String... args){if(!users.existsByUsername("admin"))users.save(new UserEntity("admin",enc.encode("admin123"),Role.ADMIN,true));if(!users.existsByUsername("caja"))users.save(new UserEntity("caja",enc.encode("caja123"),Role.CASHIER,true));if(tables.count()==0){for(int i=1;i<=10;i++){var t=new BarTable();t.setName("Mesa "+i);t.setActive(true);tables.save(t);}var b=new BarTable();b.setName("Barra");b.setActive(true);tables.save(b);}if(products.count()==0){p("Victoria media","Cerveza","25","18",48,10);p("Corona media","Cerveza","25","18",48,10);p("Caguama Victoria","Cerveza","55","42",24,6);p("Caguama Corona","Cerveza","55","42",24,6);p("Michelada sencilla","Preparado","45","27",50,10);p("Michelada especial","Preparado","60","35",50,10);p("Maruchan","Comida","35","22",20,5);p("Botana","Botana","20","10",30,5);p("Agua mineral","Extras","20","12",24,6);p("Vaso preparado","Extras","15","7",100,20);}}private void p(String n,String c,String price,String cost,Integer stock,Integer alert){var p=new Product();p.setName(n);p.setCategory(c);p.setPrice(new BigDecimal(price));p.setCostPrice(new BigDecimal(cost));p.setStock(stock);p.setLowStockAlert(alert);p.setActive(true);products.save(p);}}
